// Step 1: Create IAM Permission Boundary to prevent privilege escalation
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "AllowOnlyServiceSpecificActions",
      "Effect": "Allow",
      "Action": [
        "s3:*",
        "dynamodb:*",
        "secretsmanager:GetSecretValue",
        "kms:Decrypt",
        "logs:*",
        "xray:*"
      ],
      "Resource": "*"
    },
    {
      "Sid": "DenyPrivilegeEscalation",
      "Effect": "Deny",
      "Action": [
        "iam:CreateUser",
        "iam:CreateAccessKey",
        "iam:CreateRole",
        "iam:AttachUserPolicy",
        "iam:AttachRolePolicy",
        "iam:PutUserPolicy",
        "iam:PutRolePolicy",
        "iam:AddUserToGroup",
        "iam:UpdateAssumeRolePolicy",
        "sts:AssumeRole",
        "lambda:CreateFunction",
        "lambda:UpdateFunctionCode",
        "ec2:RunInstances"
      ],
      "Resource": "*"
    }
  ]
}

// Step 2: Lambda Execution Role with Boundary
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": "sts:AssumeRole",
      "Principal": {
        "Service": "lambda.amazonaws.com"
      }
    }
  ]
}

// Step 3: CloudFormation template for Lambda with restricted role
{
  "AWSTemplateFormatVersion": "2010-09-09",
  "Resources": {
    "DataProcessorLambdaRole": {
      "Type": "AWS::IAM::Role",
      "Properties": {
        "RoleName": "data-processor-lambda-role",
        "AssumeRolePolicyDocument": {
          "Version": "2012-10-17",
          "Statement": [
            {
              "Effect": "Allow",
              "Principal": {"Service": "lambda.amazonaws.com"},
              "Action": "sts:AssumeRole"
            }
          ]
        },
        "PermissionsBoundary": "arn:aws:iam::123456789012:policy/LambdaPermissionBoundary",
        "ManagedPolicyArns": [
          "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
        ],
        "Policies": [
          {
            "PolicyName": "S3ReadOnlyAccess",
            "PolicyDocument": {
              "Version": "2012-10-17",
              "Statement": [
                {
                  "Effect": "Allow",
                  "Action": ["s3:GetObject", "s3:ListBucket"],
                  "Resource": [
                    "arn:aws:s3:::my-app-data/*",
                    "arn:aws:s3:::my-app-data"
                  ]
                }
              ]
            }
          }
        ]
      }
    },
    "DataProcessorLambda": {
      "Type": "AWS::Lambda::Function",
      "Properties": {
        "FunctionName": "data-processor",
        "Runtime": "python3.11",
        "Role": {"Fn::GetAtt": ["DataProcessorLambdaRole", "Arn"]},
        "Handler": "index.handler",
        "Code": {
          "ZipFile": "def handler(event, context): return {'statusCode': 200}"
        },
        "Environment": {
          "Variables": {
            "FUNCTION_NAME": "data-processor"
          }
        }
      }
    }
  }
}

// Step 4: Service Control Policy (SCP) for Organization
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Sid": "PreventIAMPrivilegeEscalation",
      "Effect": "Deny",
      "Action": [
        "iam:CreateAccessKey",
        "iam:CreateUser",
        "iam:AttachUserPolicy",
        "iam:PutUserPolicy"
      ],
      "Resource": "*",
      "Condition": {
        "StringNotEquals": {
          "aws:PrincipalOrgID": "o-xxxxxxxxxx"
        }
      }
    }
  ]
}

