// - PrivilegeEscalation:IAMUser/AdministrativePermissions
// - UnauthorizedAccess:IAMUser/InstanceCredentialExfiltration
// - Stealth:IAMUser/CloudTrailLoggingDisabled

// Security Hub query (AWS Config)
SELECT 
  resourceId,
  resourceType,
  configuration.roleName,
  configuration.attachedManagedPolicies
FROM 
  aws_iam_role
WHERE 
  configuration.attachedManagedPolicies LIKE '%AdministratorAccess%'
  OR configuration.attachedManagedPolicies LIKE '%PowerUserAccess%'
